import { useEffect, useState } from "react";
import { Eye, BarChart3, Volume2, Activity, Menu, X } from "lucide-react";
import Sidebar from "../components/Sidebar";
import MetricCard from "../components/MetricCard";
import AIPrediction from "../components/AIPrediction";
import WelcomeMessage from "../components/WelcomeMessage";
import ChartArea from "../components/ChartArea";
import { fetchCompanies } from "../utils/api";

const StockDashboard = () => {
  const [companies, setCompanies] = useState([]);
  const [selectedCompany, setSelectedCompany] = useState(null);
  const [searchTerm, setSearchTerm] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const [sidebarOpen, setSidebarOpen] = useState(true);

  // ✅ Fetch companies on mount
  useEffect(() => {
    const loadCompanies = async () => {
      setIsLoading(true);
      try {
        const res = await fetchCompanies();
        setCompanies(Array.isArray(res) ? res : []);
      } catch (err) {
        console.error("Error fetching companies:", err);
      } finally {
        setIsLoading(false);
      }
    };
    loadCompanies();
  }, []);

  // ✅ Safe search
  const filteredCompanies = companies.filter(
    (c) =>
      c?.name?.toLowerCase().includes(searchTerm.toLowerCase()) ||
      c?.symbol?.toLowerCase().includes(searchTerm.toLowerCase())
  );

  // ✅ Handle selection
  const handleCompanySelect = (company) => {
    setSelectedCompany(company);
    setIsLoading(true);
    setTimeout(() => setIsLoading(false), 1000); // mock load
  };

  // ✅ Prepare chart data
  const chartData =
    selectedCompany?.historical_data?.length > 0
      ? {
          labels: selectedCompany.historical_data.map((d) => d.date || ""),
          datasets: [
            {
              data: selectedCompany.historical_data.map(
                (d) => Number(d.close || d.price) || 0
              ),
              borderColor: "#3b82f6",
              backgroundColor: "rgba(59, 130, 246, 0.08)",
              borderWidth: 3,
              fill: true,
            },
          ],
        }
      : { labels: [], datasets: [] };

  return (
    <div className="flex flex-col md:flex-row h-screen bg-gradient-to-br from-slate-50 to-blue-50">
      {/* Sidebar Component */}
      <div
        className={`transition-all duration-300 fixed md:static z-20 h-full bg-white ${
          sidebarOpen ? "w-72 sm:w-80 md:w-96" : "w-0"
        }`}
      >
        <div className={`${sidebarOpen ? "block" : "hidden"} h-full`}>
          <Sidebar
            companies={companies}
            filteredCompanies={filteredCompanies}
            searchTerm={searchTerm}
            setSearchTerm={setSearchTerm}
            selectedCompany={selectedCompany}
            handleCompanySelect={handleCompanySelect}
          />
        </div>
      </div>

      {/* Main Content */}
      <div className="flex-1 flex flex-col overflow-hidden">
        {/* Toggle Button (always visible on mobile) */}
        <div className="p-4 bg-white shadow-sm border-b border-gray-200 flex justify-between items-center">
          <button
            onClick={() => setSidebarOpen(!sidebarOpen)}
            className="flex items-center gap-2 px-3 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors md:hidden"
          >
            {sidebarOpen ? <X size={20} /> : <Menu size={20} />}
            <span className="text-sm">
              {sidebarOpen ? "Hide Sidebar" : "Show Sidebar"}
            </span>
          </button>
          <h2 className="hidden md:block text-lg font-semibold text-gray-700">
            Stock Dashboard
          </h2>
        </div>

        {/* Company Info + Metrics */}
        {selectedCompany && (
          <div className="p-4 md:p-6 bg-white shadow-sm border-b border-gray-200">
            <div className="flex flex-col xl:flex-row xl:items-center xl:justify-between gap-6">
              {/* Company Info */}
              <div className="flex items-center gap-3 md:gap-4">
                <div className="w-12 h-12 md:w-16 md:h-16 bg-gradient-to-br from-blue-600 to-indigo-600 rounded-xl md:rounded-2xl flex items-center justify-center text-white font-bold text-lg md:text-xl shadow-lg">
                  {selectedCompany.symbol?.substring(0, 2)}
                </div>
                <div>
                  <h1 className="text-lg md:text-2xl font-bold text-gray-900 mb-1">
                    {selectedCompany.name}
                  </h1>
                  <div className="flex flex-wrap items-center gap-2 md:gap-3 text-xs md:text-sm text-gray-600">
                    <span className="px-2 py-0.5 md:px-3 md:py-1 bg-blue-50 text-blue-700 rounded-full font-medium">
                      {selectedCompany.symbol}
                    </span>
                    <span>NSE</span>
                    <span>•</span>
                    <span>{selectedCompany.sector}</span>
                  </div>
                </div>
              </div>

              {/* Metrics */}
              <div className="grid grid-cols-2 sm:grid-cols-2 lg:grid-cols-4 gap-3 md:gap-6 w-full xl:w-auto">
                <MetricCard
                  label="Current Price"
                  value={`₹${Number(selectedCompany?.current_price).toFixed(2)}`}
                  icon={Eye}
                  subValue={`${
                    Number(selectedCompany?.change) >= 0 ? "+" : ""
                  }₹${Number(selectedCompany?.change || 0).toFixed(2)} (${
                    Number(
                      selectedCompany?.change_percent ??
                        selectedCompany?.changePercent
                    ).toFixed(2) || "0.00"
                  }%)`}
                />
                <MetricCard
                  label="Market Cap"
                  value={selectedCompany?.market_cap || "—"}
                  icon={BarChart3}
                  subValue="Total value"
                />
                <MetricCard
                  label="Volume"
                  value={selectedCompany?.volume || "—"}
                  icon={Volume2}
                  subValue="Today's trading"
                />
                <MetricCard
                  label="P/E Ratio"
                  value={selectedCompany?.pe || "—"}
                  icon={Activity}
                  subValue="Price to earnings"
                />
              </div>
            </div>
          </div>
        )}

        {/* Chart + AI Prediction / Welcome */}
        <div className="flex-1 p-4 md:p-6 grid grid-cols-1 lg:grid-cols-3 gap-4 md:gap-6 overflow-y-auto">
          {selectedCompany ? (
            <>
              {/* Chart Area */}
              <div className="lg:col-span-2 bg-white rounded-xl md:rounded-2xl shadow-md p-4 h-[300px] md:h-[400px]">
                <ChartArea
                  selectedCompany={selectedCompany}
                  isLoading={isLoading}
                  chartData={chartData}
                />
              </div>

              {/* AI Predictions */}
              <div className="lg:col-span-1 bg-white rounded-xl md:rounded-2xl shadow-md border border-gray-200 p-4">
                <AIPrediction company={selectedCompany} isLoading={isLoading} />
              </div>
            </>
          ) : (
            <div className="col-span-1 lg:col-span-3 flex items-center justify-center">
              <WelcomeMessage />
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default StockDashboard;
